 47→export function parseEvidenceRef(ref: string): ParsedEvidenceRef | undefined {
 48→  const colonIndex = ref.indexOf(":");
 49→  if (colonIndex <= 0 || colonIndex === ref.length - 1) return undefined;
 50→
 51→  const table = ref.slice(0, colonIndex);
 52→  const rawId = stripRecordIdEscaping(ref.slice(colonIndex + 1));
 53→
 54→  if (!EVIDENCE_TABLE_ALLOWLIST.has(table)) return undefined;
 55→
 56→  return { table, id: rawId, record: new RecordId(table, rawId) };
 57→}
