 97→  verifiedCount: number;
 98→  failedRefs: string[];
 99→  warnings: string[];
100→};
101→
102→export function classifyQueryResults(
103→  parsedRefs: ParsedEvidenceRef[],
104→  queryRows: EvidenceQueryRow[],
105→  workspaceId: RecordId,
106→  intentCreatedAt?: Date,
107→): ClassificationResult {
108→  if (parsedRefs.length === 0) {
109→    return { verifiedCount: 0, failedRefs: [], warnings: [] };
110→  }
111→
112→  // Build a lookup map: "table:id" -> query row
113→  const rowMap = new Map<string, EvidenceQueryRow>();
114→  for (const row of queryRows) {
115→    const key = `${row.id.table.name}:${row.id.id}`;
116→    rowMap.set(key, row);
117→  }
118→
119→  // Normalize workspace ID: strip SurrealDB angle-bracket escaping and table prefix.
120→  // The workspace RecordId may arrive via JSON (EVENT webhook) with the full string
121→  // representation embedded in .id (e.g. "workspace:⟨uuid⟩"), or as a clean UUID.
122→  const normalizeWsId = (id: unknown): string => {
123→    const s = String(id);
124→    // Strip table prefix if present (e.g. "workspace:⟨uuid⟩" -> "⟨uuid⟩")
125→    const afterColon = s.includes(":") ? s.slice(s.indexOf(":") + 1) : s;
126→    return stripRecordIdEscaping(afterColon);
127→  };
