129→  let verifiedCount = 0;
130→  const failedRefs: string[] = [];
131→  const warnings: string[] = [];
132→
133→  for (const ref of parsedRefs) {
134→    const key = `${ref.table}:${ref.id}`;
135→    const row = rowMap.get(key);
136→
137→    if (!row) {
138→      failedRefs.push(key);
139→      warnings.push(`${key} not found`);
140→      continue;
141→    }
142→
143→    // Check workspace scope
144→    const rowWsId = normalizeWsId(row.workspace.id);
145→    if (rowWsId !== targetWsId) {
146→      failedRefs.push(key);
147→      warnings.push(`${key} belongs to a different workspace`);
148→      continue;
149→    }
150→
151→    // Check liveness: entity status must be in the valid set for its table
152→    const validStatuses = VALID_EVIDENCE_STATUSES[ref.table];
153→    if (validStatuses && row.status && !validStatuses.has(row.status)) {
154→      failedRefs.push(key);
155→      warnings.push(`${key} has status '${row.status}' which is not live`);
156→      continue;
157→    }
158→
159→    // Check temporal ordering: evidence must have been created before the intent
160→    if (intentCreatedAt && row.created_at) {
161→      const toMs = (d: unknown): number =>
