  1→/**
  2→ * Context Injector -- Pure functions for brain-context injection
  3→ *
  4→ * Responsible for:
  5→ * 1. Ranking context candidates by weighted cosine similarity
  6→ * 2. Selecting top N within token budget
  7→ * 3. Building <brain-context> XML block
  8→ * 4. Injecting into system prompt (string or array form)
  9→ *
 10→ * All functions are pure -- no IO, no side effects.
 11→ * The orchestration (embedding, cache, DB queries) lives in the proxy route.
 12→ */
 13→import { RecordId } from "surrealdb";
 14→import { extractSearchTerms } from "../graph/bm25-search";
 15→import { applyRrf, type RrfItem } from "../graph/rrf";
 16→
 17→// ---------------------------------------------------------------------------
 18→// Local cosine similarity (kept for legacy rankCandidates; no external dep)
 19→// ---------------------------------------------------------------------------
 20→
 21→function cosineSimilarity(a: number[], b: number[]): number {
 22→  if (a.length !== b.length || a.length === 0) return -1;
 23→  let dot = 0, normA = 0, normB = 0;
 24→  for (let i = 0; i < a.length; i++) {
 25→    dot += a[i] * b[i];
 26→    normA += a[i] * a[i];
 27→    normB += b[i] * b[i];
 28→  }
 29→  if (normA === 0 || normB === 0) return -1;
 30→  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
 31→}
 32→
 33→// ---------------------------------------------------------------------------
 34→// Types
 35→// ---------------------------------------------------------------------------
 36→
 37→export type ContextCandidate = {
 38→  readonly id: string;
 39→  readonly type: "decision" | "learning" | "observation";
 40→  readonly text: string;
 41→  readonly embedding?: number[];
 42→  readonly weight: number;
 43→};
 44→
 45→export type Bm25ContextCandidate = {
 46→  readonly id: string;
 47→  readonly type: "decision" | "learning" | "observation";
 48→  readonly text: string;
 49→  readonly bm25Score: number;
 50→  readonly updatedAt: string;
 51→};
 52→
 53→export type RankedCandidate = {
 54→  readonly id: string;
 55→  readonly type: "decision" | "learning" | "observation";
 56→  readonly text: string;
 57→  readonly score: number;
 58→};
 59→
 60→export type InjectionResult = {
 61→  readonly system: string | Array<{ type: string; text: string; cache_control?: { type: string } }>;
 62→  readonly injected: boolean;
 63→  readonly tokensEstimated: number;
 64→  readonly decisionsCount: number;
 65→  readonly learningsCount: number;
 66→  readonly observationsCount: number;
 67→};
 68→
 69→type SystemPrompt = string | Array<{ type: string; text: string; cache_control?: { type: string } }> | undefined;
 70→
 71→// ---------------------------------------------------------------------------
 72→// Recent Changes Types (04-01: vector search classification)
 73→// ---------------------------------------------------------------------------
 74→
 75→export type RecentChangeCandidate = {
 76→  readonly id: string;
 77→  readonly table: "decision" | "task" | "observation";
 78→  readonly text: string;
 79→  readonly similarity: number;
 80→  readonly updatedAt: string;
 81→};
 82→
 83→export type ClassifiedChange = RecentChangeCandidate & {
 84→  readonly classification: "urgent-context" | "context-update";
 85→};
 86→
 87→// ---------------------------------------------------------------------------
 88→// Token Estimation (pure, ~4 chars per token)
 89→// ---------------------------------------------------------------------------
 90→
 91→export function estimateTokenCount(text: string): number {
 92→  return Math.ceil(text.length / 4);
 93→}
 94→
 95→// ---------------------------------------------------------------------------
 96→// Ranking: weighted cosine similarity
 97→// ---------------------------------------------------------------------------
 98→
 99→export function rankCandidates(
100→  candidates: ContextCandidate[],
101→  queryEmbedding: number[],
102→): RankedCandidate[] {
103→  return candidates
104→    .map((c) => {
105→      const hasEmbedding = c.embedding !== undefined && c.embedding.length > 0;
106→      const score = hasEmbedding
107→        ? cosineSimilarity(c.embedding!, queryEmbedding) * c.weight
108→        : c.weight * 0.5;
109→      return { id: c.id, type: c.type, text: c.text, score };
110→    })
111→    .sort((a, b) => b.score - a.score);
112→}
113→
114→// ---------------------------------------------------------------------------
115→// BM25 + Recency Ranking (02-01: pure functions)
116→// ---------------------------------------------------------------------------
117→
118→const DEFAULT_RECENCY_HALFLIFE_HOURS = 168; // 1 week
119→
120→/**
121→ * Compute exponential recency decay factor.
122→ * decayFactor = exp(-ageHours / halflife)
123→ *
124→ * Returns 1.0 for zero or negative age (future timestamps treated as fresh).
125→ */
126→export function computeRecencyDecay(ageHours: number, halflife: number): number {
127→  if (ageHours <= 0) return 1.0;
128→  return Math.exp(-ageHours / halflife);
129→}
130→
131→/**
132→ * Compute final context score: BM25 relevance weighted by recency decay.
133→ * finalScore = bm25Score * exp(-ageHours / halflife)
134→ */
135→export function computeFinalScore(
136→  bm25Score: number,
137→  updatedAt: string,
138→  now: Date,
139→  halflife: number,
140→): number {
141→  const ageMs = now.getTime() - new Date(updatedAt).getTime();
142→  const ageHours = ageMs / (1000 * 60 * 60);
143→  return bm25Score * computeRecencyDecay(ageHours, halflife);
144→}
145→
146→/**
147→ * Rank BM25 context candidates by combined relevance and recency.
148→ * Pure pipeline: map to final scores, sort descending.
149→ */
150→export function rankByBm25WithRecency(
151→  candidates: Bm25ContextCandidate[],
152→  now: Date,
153→  halflife: number = DEFAULT_RECENCY_HALFLIFE_HOURS,
154→): RankedCandidate[] {
155→  return candidates
156→    .map((c) => ({
157→      id: c.id,
158→      type: c.type,
159→      text: c.text,
160→      score: computeFinalScore(c.bm25Score, c.updatedAt, now, halflife),
161→    }))
162→    .sort((a, b) => b.score - a.score);
163→}
164→
165→// ---------------------------------------------------------------------------
166→// Budget Selection: top N within token budget
167→// ---------------------------------------------------------------------------
168→
169→export function selectWithinBudget(
170→  ranked: RankedCandidate[],
171→  tokenBudget: number,
172→): RankedCandidate[] {
173→  const selected: RankedCandidate[] = [];
174→  let tokensUsed = 0;
175→
176→  for (const candidate of ranked) {
177→    const candidateTokens = estimateTokenCount(candidate.text);
178→    if (tokensUsed + candidateTokens > tokenBudget) break;
179→    selected.push(candidate);
180→    tokensUsed += candidateTokens;
181→  }
182→
183→  return selected;
184→}
185→
186→// ---------------------------------------------------------------------------
187→// XML Block Construction
188→// ---------------------------------------------------------------------------
189→
190→export function buildBrainContextXml(selected: RankedCandidate[]): string {
191→  if (selected.length === 0) return "";
192→
193→  const decisions = selected.filter((c) => c.type === "decision");
194→  const learnings = selected.filter((c) => c.type === "learning");
195→  const observations = selected.filter((c) => c.type === "observation");
196→
197→  const sections: string[] = [];
198→
199→  if (decisions.length > 0) {
200→    const items = decisions.map((d) => `  <item>${d.text}</item>`).join("\n");
201→    sections.push(`<decisions>\n${items}\n</decisions>`);
202→  }
203→
204→  if (learnings.length > 0) {
205→    const items = learnings.map((l) => `  <item>${l.text}</item>`).join("\n");
206→    sections.push(`<learnings>\n${items}\n</learnings>`);
207→  }
208→
209→  if (observations.length > 0) {
210→    const items = observations.map((o) => `  <item>${o.text}</item>`).join("\n");
211→    sections.push(`<observations>\n${items}\n</observations>`);
212→  }
213→
214→  return `<brain-context>\n${sections.join("\n")}\n</brain-context>`;
215→}
216→
217→// ---------------------------------------------------------------------------
218→// System Prompt Injection
219→// ---------------------------------------------------------------------------
220→
221→export function injectBrainContext(
222→  originalSystem: SystemPrompt,
223→  brainContextXml: string,
224→): InjectionResult {
225→  if (!brainContextXml) {
226→    return {
227→      system: originalSystem ?? "",
228→      injected: false,
229→      tokensEstimated: 0,
230→      decisionsCount: 0,
231→      learningsCount: 0,
232→      observationsCount: 0,
233→    };
234→  }
235→
236→  const tokensEstimated = estimateTokenCount(brainContextXml);
237→
238→  // Count items in XML (by counting <item> tags per section)
239→  const decisionsCount = (brainContextXml.match(/<decisions>[\s\S]*?<\/decisions>/)?.[0]?.match(/<item>/g) ?? []).length;
240→  const learningsCount = (brainContextXml.match(/<learnings>[\s\S]*?<\/learnings>/)?.[0]?.match(/<item>/g) ?? []).length;
241→  const observationsCount = (brainContextXml.match(/<observations>[\s\S]*?<\/observations>/)?.[0]?.match(/<item>/g) ?? []).length;
242→
243→  if (Array.isArray(originalSystem)) {
244→    // Array-form: append brain-context as additional text block with cache_control: ephemeral
245→    const enriched = [
246→      ...originalSystem,
247→      {
248→        type: "text",
249→        text: brainContextXml,
250→        cache_control: { type: "ephemeral" },
251→      },
252→    ];
253→
254→    return {
255→      system: enriched,
256→      injected: true,
257→      tokensEstimated,
258→      decisionsCount,
259→      learningsCount,
260→      observationsCount,
261→    };
262→  }
263→
264→  if (typeof originalSystem === "string") {
265→    // String-form: append brain-context after original text
266→    return {
267→      system: `${originalSystem}\n\n${brainContextXml}`,
268→      injected: true,
269→      tokensEstimated,
270→      decisionsCount,
271→      learningsCount,
272→      observationsCount,
273→    };
274→  }
275→
276→  // No original system prompt: use brain-context as system prompt
277→  return {
278→    system: brainContextXml,
279→    injected: true,
280→    tokensEstimated,
281→    decisionsCount,
282→    learningsCount,
283→    observationsCount,
284→  };
285→}
286→
287→// ---------------------------------------------------------------------------
288→// Recent Changes Injection into System Prompt (04-02: pure)
289→// ---------------------------------------------------------------------------
290→
291→/**
292→ * Injects recent changes XML into a system prompt with correct ordering:
293→ * - <urgent-context> is injected BEFORE <brain-context>
294→ * - <context-update> is injected AFTER <brain-context>
295→ *
296→ * For array-form system prompts, each block becomes a separate text element
297→ * with cache_control: ephemeral.
298→ */
299→export function injectRecentChanges(
300→  system: SystemPrompt,
301→  recentChangesXml: string,
302→): InjectionResult["system"] {
303→  if (!recentChangesXml) return system ?? "";
304→
305→  // Extract urgent-context and context-update blocks from the XML
306→  const urgentMatch = recentChangesXml.match(/<urgent-context>[\s\S]*?<\/urgent-context>/);
307→  const updateMatch = recentChangesXml.match(/<context-update>[\s\S]*?<\/context-update>/);
308→
309→  const urgentBlock = urgentMatch?.[0] ?? "";
310→  const updateBlock = updateMatch?.[0] ?? "";
311→
312→  if (!urgentBlock && !updateBlock) return system ?? "";
313→
314→  if (Array.isArray(system)) {
315→    const result = [...system];
316→
317→    // Find the brain-context block index for insertion ordering
318→    const brainContextIdx = result.findIndex(
319→      (block) => typeof block.text === "string" && block.text.includes("<brain-context>"),
320→    );
321→
322→    if (brainContextIdx >= 0) {
323→      // Insert urgent BEFORE brain-context, update AFTER
324→      if (updateBlock) {
325→        result.splice(brainContextIdx + 1, 0, {
326→          type: "text",
327→          text: updateBlock,
328→          cache_control: { type: "ephemeral" },
329→        });
330→      }
331→      if (urgentBlock) {
332→        result.splice(brainContextIdx, 0, {
333→          type: "text",
334→          text: urgentBlock,
335→          cache_control: { type: "ephemeral" },
336→        });
337→      }
338→    } else {
339→      // No brain-context block -- append both at end (urgent first, then update)
340→      if (urgentBlock) {
341→        result.push({ type: "text", text: urgentBlock, cache_control: { type: "ephemeral" } });
342→      }
343→      if (updateBlock) {
344→        result.push({ type: "text", text: updateBlock, cache_control: { type: "ephemeral" } });
345→      }
346→    }
347→
348→    return result;
349→  }
350→
351→  if (typeof system === "string") {
352→    // String-form: find <brain-context> position for ordering
353→    const brainContextPos = system.indexOf("<brain-context>");
354→
355→    if (brainContextPos >= 0) {
356→      const brainContextEnd = system.indexOf("</brain-context>");
357→      const afterBrainContext = brainContextEnd >= 0
358→        ? brainContextEnd + "</brain-context>".length
359→        : system.length;
360→
361→      const before = system.slice(0, brainContextPos);
362→      const brainSection = system.slice(brainContextPos, afterBrainContext);
363→      const after = system.slice(afterBrainContext);
364→
365→      const parts = [before.trimEnd()];
366→      if (urgentBlock) parts.push(urgentBlock);
367→      parts.push(brainSection);
368→      if (updateBlock) parts.push(updateBlock);
369→      parts.push(after.trimStart());
370→
371→      return parts.filter(Boolean).join("\n\n");
372→    }
373→
374→    // No brain-context -- append both
375→    const parts = [system];
376→    if (urgentBlock) parts.push(urgentBlock);
377→    if (updateBlock) parts.push(updateBlock);
378→    return parts.join("\n\n");
379→  }
380→
381→  // No existing system prompt -- combine blocks
382→  const parts: string[] = [];
383→  if (urgentBlock) parts.push(urgentBlock);
384→  if (updateBlock) parts.push(updateBlock);
385→  return parts.join("\n\n");
386→}
387→
388→// ---------------------------------------------------------------------------
389→// Recent Changes Classification (02-02: time-based, replaces similarity thresholds)
390→// ---------------------------------------------------------------------------
391→
392→const URGENT_AGE_MINUTES = 30;
393→const RECENT_AGE_HOURS = 24;
394→
395→/**
396→ * Classifies context items by age into urgent-context or context-update.
397→ *
398→ * - <= 30 minutes old  -> urgent-context (agent should act on this immediately)
399→ * - <= 24 hours old    -> context-update (background awareness)
400→ * - > 24 hours old     -> filtered out (stale)
401→ *
402→ * Pure function: takes explicit `now` for deterministic testing.
403→ * Preserves input order for candidates that pass the age filter.
404→ */
405→export function classifyByAge(
406→  candidates: RecentChangeCandidate[],
407→  now: Date,
408→): ClassifiedChange[] {
409→  const urgentThresholdMs = URGENT_AGE_MINUTES * 60 * 1000;
410→  const recentThresholdMs = RECENT_AGE_HOURS * 60 * 60 * 1000;
411→
412→  return candidates
413→    .map((c) => {
414→      const ageMs = now.getTime() - new Date(c.updatedAt).getTime();
415→      if (ageMs > recentThresholdMs) return undefined;
416→      return {
417→        ...c,
418→        classification: ageMs <= urgentThresholdMs
419→          ? "urgent-context" as const
420→          : "context-update" as const,
421→      };
422→    })
423→    .filter((c): c is ClassifiedChange => c !== undefined);
424→}
425→
426→/**
427→ * @deprecated Use classifyByAge instead. Kept for backwards compatibility during migration.
428→ */
429→export function classifyBySimilarity(
430→  candidates: RecentChangeCandidate[],
431→): ClassifiedChange[] {
432→  return classifyByAge(candidates, new Date());
433→}
434→
435→// ---------------------------------------------------------------------------
436→// Recent Changes XML Builder (04-01: pure)
437→// ---------------------------------------------------------------------------
438→
439→/**
440→ * Builds an XML block for recent graph changes classified by urgency.
441→ *
442→ * Output structure:
443→ * <recent-changes>
444→ *   <urgent-context>
445→ *     <item type="decision">Use tRPC for all APIs</item>
446→ *   </urgent-context>
447→ *   <context-update>
448→ *     <item type="task">Implement rate limiting</item>
449→ *   </context-update>
450→ * </recent-changes>
451→ */
452→function escapeXml(text: string): string {
453→  return text
454→    .replace(/&/g, "&amp;")
455→    .replace(/</g, "&lt;")
456→    .replace(/>/g, "&gt;")
457→    .replace(/"/g, "&quot;");
458→}
459→
460→export function buildRecentChangesXml(changes: ClassifiedChange[]): string {
461→  if (changes.length === 0) return "";
462→
463→  const urgent = changes.filter((c) => c.classification === "urgent-context");
464→  const updates = changes.filter((c) => c.classification === "context-update");
465→
466→  const sections: string[] = [];
467→
468→  if (urgent.length > 0) {
469→    const items = urgent
470→      .map((c) => `  <item type="${escapeXml(c.table)}">${escapeXml(c.text)}</item>`)
471→      .join("\n");
472→    sections.push(`<urgent-context>\n${items}\n</urgent-context>`);
473→  }
474→
475→  if (updates.length > 0) {
476→    const items = updates
477→      .map((c) => `  <item type="${escapeXml(c.table)}">${escapeXml(c.text)}</item>`)
478→      .join("\n");
479→    sections.push(`<context-update>\n${items}\n</context-update>`);
480→  }
481→
482→  return `<recent-changes>\n${sections.join("\n")}\n</recent-changes>`;
483→}
