485→// ---------------------------------------------------------------------------
486→// Time-Based Recent Changes (02-03: pure functions)
487→// ---------------------------------------------------------------------------
488→
489→/**
490→ * Row shape returned by time-based entity queries.
491→ * Used by mapRowsToRecentChanges to produce RecentChangeCandidate[].
492→ */
493→export type TimeBasedChangeRow = {
494→  readonly id: string;
495→  readonly text: string;
496→  readonly updated_at: string;
497→};
498→
499→/**
500→ * Compute a cutoff Date by subtracting windowMs from now.
501→ * Pure date arithmetic -- no IO.
502→ */
503→export function buildTimeWindowCutoff(now: Date, windowMs: number): Date {
504→  return new Date(now.getTime() - windowMs);
505→}
506→
507→/**
508→ * Transform raw DB rows into RecentChangeCandidate[].
509→ *
510→ * Sets similarity to 1.0 for all items since time-based retrieval
511→ * does not produce relevance scores -- all items within the window
512→ * are equally relevant by definition.
513→ */
514→export function mapRowsToRecentChanges(
515→  rows: TimeBasedChangeRow[],
516→  table: RecentChangeCandidate["table"],
517→): RecentChangeCandidate[] {
518→  return rows.map((row) => ({
519→    id: row.id,
520→    table,
521→    text: row.text,
522→    similarity: 1.0,
523→    updatedAt: row.updated_at,
524→  }));
525→}
