527→// ---------------------------------------------------------------------------
528→// Time-Based Recent Changes Adapter (02-03: replaces BM25 search)
529→// ---------------------------------------------------------------------------
530→
531→/**
532→ * Port signature for fetching recent graph changes by time window.
533→ * No text query needed -- pure time-ordered retrieval.
534→ */
535→export type FetchRecentChangesByTime = (
536→  workspaceId: string,
537→  cutoff: Date,
538→  limit: number,
539→) => Promise<RecentChangeCandidate[]>;
540→
541→type TimeBasedDbRow = {
542→  id: RecordId;
543→  text: string;
544→  updated_at: string;
545→};
546→
547→/**
548→ * Fetches recent graph entity changes by time window using simple
549→ * WHERE updated_at > $cutoff queries. No embeddings, no BM25.
550→ *
551→ * Results are ordered by updated_at DESC -- most recent first.
552→ */
553→export function createFetchRecentChangesByTime(
554→  surreal: { query: <T>(sql: string, vars?: Record<string, unknown>) => Promise<T> },
555→): FetchRecentChangesByTime {
556→  return async (
557→    workspaceId: string,
558→    cutoff: Date,
559→    limit: number,
560→  ): Promise<RecentChangeCandidate[]> => {
561→    const workspaceRecord = new RecordId("workspace", workspaceId);
562→
563→    const results = await surreal.query<[TimeBasedDbRow[], TimeBasedDbRow[], TimeBasedDbRow[]]>(
564→      `SELECT id, summary AS text, updated_at
565→         FROM decision WHERE workspace = $ws AND updated_at > $cutoff AND status != "superseded"
566→         ORDER BY updated_at DESC LIMIT $limit;
567→       SELECT id, title AS text, updated_at
568→         FROM task WHERE workspace = $ws AND updated_at > $cutoff
569→         ORDER BY updated_at DESC LIMIT $limit;
570→       SELECT id, text, updated_at
571→         FROM observation WHERE workspace = $ws AND updated_at > $cutoff
572→         ORDER BY updated_at DESC LIMIT $limit;`,
573→      { ws: workspaceRecord, cutoff: cutoff.toISOString(), limit },
574→    );
575→
576→    function toRecentChanges(
577→      rows: TimeBasedDbRow[],
578→      table: RecentChangeCandidate["table"],
579→    ): RecentChangeCandidate[] {
580→      return rows.map((row) => ({
581→        id: (row.id as RecordId).id as string,
582→        table,
583→        text: row.text,
584→        similarity: 1.0,
585→        updatedAt: row.updated_at,
586→      }));
587→    }
588→
589→    return [
590→      ...toRecentChanges(results[0] ?? [], "decision"),
591→      ...toRecentChanges(results[1] ?? [], "task"),
592→      ...toRecentChanges(results[2] ?? [], "observation"),
593→    ];
594→  };
595→}
