597→// ---------------------------------------------------------------------------
598→// Recent Changes BM25 Search (04-01 / 02-01: adapter boundary -- DB side effect)
599→// ---------------------------------------------------------------------------
600→
601→/**
602→ * Port signature for searching recent graph changes by BM25 text relevance.
603→ * No embedding API calls -- uses fulltext indexes with recency filtering.
604→ */
605→export type SearchRecentChanges = (
606→  queryText: string,
607→  workspaceId: string,
608→  lastRequestAt: Date,
609→) => Promise<RecentChangeCandidate[]>;
610→
611→type Bm25RecentRow = {
612→  id: RecordId;
613→  text: string;
614→  score: number;
615→  updated_at: string;
616→};
617→
618→/**
619→ * Searches for recent graph entity changes relevant to a text query using BM25.
620→ *
621→ * Replaces KNN vector search (02-01): no embedding generation needed.
622→ * Uses BM25 fulltext indexes on decision.summary, task.title, observation.text.
623→ */
624→export function createSearchRecentChanges(
625→  surreal: { query: <T>(sql: string, vars?: Record<string, unknown>) => Promise<T> },
626→): SearchRecentChanges {
627→  return async (
628→    queryText: string,
629→    workspaceId: string,
630→    lastRequestAt: Date,
631→  ): Promise<RecentChangeCandidate[]> => {
632→    // BM25 @N@ does AND matching — use OR across separate predicates per term.
633→    // See: https://surrealdb.com/docs/surrealdb/models/full-text-search
634→    const termList = extractSearchTerms(queryText)
635→      .split(" ")
636→      .filter((t) => t.length > 0);
637→    if (termList.length === 0) return [];
638→
639→    const workspaceRecord = new RecordId("workspace", workspaceId);
640→    const limit = 20;
641→
642→    // Build OR-predicate clauses for each table
643→    const scoreExpr = termList.map((_, i) => `search::score(${i})`).join(" + ");
644→    const bindings: Record<string, unknown> = { ws: workspaceRecord, since: lastRequestAt, limit };
645→    termList.forEach((term, i) => { bindings[`t${i}`] = term; });
646→
647→    const matchClause = (field: string) =>
648→      termList.map((_, i) => `${field} @${i}@ $t${i}`).join(" OR ");
649→
650→    const sql = `SELECT id, summary AS text, ${scoreExpr} AS score, updated_at
651→         FROM decision WHERE (${matchClause("summary")}) AND workspace = $ws AND updated_at > $since AND status != "superseded"
652→         ORDER BY score DESC LIMIT $limit;
653→       SELECT id, title AS text, ${scoreExpr} AS score, updated_at
654→         FROM task WHERE (${matchClause("title")}) AND workspace = $ws AND updated_at > $since
655→         ORDER BY score DESC LIMIT $limit;
656→       SELECT id, text, ${scoreExpr} AS score, updated_at
657→         FROM observation WHERE (${matchClause("text")}) AND workspace = $ws AND updated_at > $since
658→         ORDER BY score DESC LIMIT $limit;`;
659→
660→    const results = await surreal.query<[Bm25RecentRow[], Bm25RecentRow[], Bm25RecentRow[]]>(
661→      sql,
662→      bindings,
663→    );
664→
665→    function toRrfItems(
666→      rows: Bm25RecentRow[],
667→      table: RecentChangeCandidate["table"],
668→    ): RrfItem<Omit<RecentChangeCandidate, "similarity">>[] {
669→      return rows.map((row) => ({
670→        _rrfKey: `${table}:${(row.id as RecordId).id as string}`,
671→        id: (row.id as RecordId).id as string,
672→        table,
673→        text: row.text,
674→        updatedAt: row.updated_at,
675→      }));
676→    }
677→
678→    const fused = applyRrf(
679→      [
680→        toRrfItems(results[0] ?? [], "decision"),
681→        toRrfItems(results[1] ?? [], "task"),
682→        toRrfItems(results[2] ?? [], "observation"),
683→      ],
684→      limit,
685→    );
686→
687→    return fused.map(({ rrfScore, ...rest }) => ({
688→      ...rest,
689→      similarity: rrfScore,
690→    }));
691→  };
692→}
693→
694→// ---------------------------------------------------------------------------
695→// BM25 Context Search (02-01: adapter boundary -- DB side effect)
696→// ---------------------------------------------------------------------------
697→
698→/**
699→ * Port signature for searching context candidates by BM25 text relevance.
